)

svc, err := adapter.New(adapter.Config{Secret: "s3cr3t", Expire: 24 * time.Hour})
if err != nil { ... }

token, err := svc.CreateToken(ctx, portal.CreateTokenInput{
	Namespace: "ns",
	Subject:   "user-1",
})
// token.Token contains the raw JWT string

claims, err := svc.Validate(ctx, *token.Token)

