GetToken() GetTokenHandler

// In portal.go:
type (
	GetTokenRequest  struct { namespace, id string }
	GetTokenResponse = *api.PortalToken
	GetTokenHandler  httptransport.Handler[GetTokenRequest, GetTokenResponse]
)

func (h *handler) GetToken() GetTokenHandler {
	return httptransport.NewHandler(
		func(ctx context.Context, r *http.Request) (GetTokenRequest, error) {
			ns, err := h.resolveNamespace(ctx)
			if err != nil { return GetTokenRequest{}, err }
			return GetTokenRequest{namespace: ns, id: chi.URLParam(r, "tokenId")}, nil
		},
		func(ctx context.Context, request GetTokenRequest) (GetTokenResponse, error) {
			token, err := h.portalService.GetToken(ctx, portal.GetTokenInput{Namespace: request.namespace, ID: request.id})
			if err != nil { return nil, err }
			res := toAPIPortalToken(token)
			return &res, nil
		},
		commonhttp.JSONResponseEncoderWithStatus[GetTokenResponse](http.StatusOK),
		httptransport.AppendOptions(h.options, httptransport.WithOperationName("getPortalToken"))...,
	)
}
